{
  "name": "MateriLib - Designer's Premium Material Hub",
  "description": "A high-end material library application for interior designers and material suppliers featuring a Pinterest-style feed, mood board creation, and a comprehensive quotation management system.",
  "requestFramePermissions": [
    "camera"
  ]
}

export type UserRole = 'DESIGNER' | 'SUPPLIER';

export interface User {
  id: string;
  email: string;
  role: UserRole;
  points: number;
  name: string;
  company?: string;
}

export enum Category {
  ST = 'ST石材',
  CT = 'CT瓷砖',
  CO = 'CO水泥',
  SF = 'SF饰面',
  WD = 'WD木材',
  GL = 'GL玻璃',
  MT = 'MT金属',
  PVC = 'PVC塑料',
  FB = 'FB面料',
  CP = 'CP地毯',
  L = 'L灯光',
  Other = '其他'
}

export interface Material {
  id: string;
  name: string;
  category: Category;
  brand: string;
  specifications: string;
  priceRange: string;
  stock: boolean;
  leadTime: string;
  fireRating: string;
  slipRating?: string;
  waterproof?: string;
  image: string;
  colors: string[];
  projectPhotos: string[];
  ratings: {
    aesthetic: number;
    durable: number;
    service: number;
    cleanliness: number;
    recommendation: number;
  };
  pointsNeeded: {
    sample: number;
    board: number;
    export: number;
  };
}

export interface MoodBoardItem {
  id: string;
  materialId: string;
  x: number;
  y: number;
  width: number;
  height: number;
  zIndex: number;
  isCustom?: boolean;
  customImage?: string;
}

export interface MoodBoard {
  id: string;
  name: string;
  items: MoodBoardItem[];
  isPrivate: boolean;
  collaborators: string[];
}

export interface QuotationRequest {
  id: string;
  materialId: string;
  designerId: string;
  projectName: string;
  projectAddress: string;
  area: number;
  deliveryDate: string;
  status: 'PENDING' | 'QUOTED' | 'ACCEPTED';
  supplierQuote?: number;
  supplierDeliveryDate?: string;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { User, UserRole, Material, Category, MoodBoard, QuotationRequest } from './types';
import { MOCK_MATERIALS } from './constants';
import Navbar from './components/Navbar';
import Auth from './components/Auth';
import PinterestFeed from './components/PinterestFeed';
import CategoryBar from './components/CategoryBar';
import MaterialDetail from './components/MaterialDetail';
import MoodBoardDesigner from './components/MoodBoardDesigner';
import SupplierDashboard from './components/SupplierDashboard';
import DesignerDashboard from './components/DesignerDashboard';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<'HOME' | 'DETAILS' | 'MOODBOARD' | 'DASHBOARD'>('HOME');
  const [selectedMaterial, setSelectedMaterial] = useState<Material | null>(null);
  const [selectedCategory, setSelectedCategory] = useState<Category | null>(null);
  const [points, setPoints] = useState(1000); // 1000 points for first 500 users

  // Navigation handlers
  const navigateToDetails = (material: Material) => {
    setSelectedMaterial(material);
    setCurrentView('DETAILS');
  };

  const handleAuthSuccess = (userData: User) => {
    setUser(userData);
    setPoints(userData.points);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentView('HOME');
  };

  if (!user) {
    return <Auth onAuthSuccess={handleAuthSuccess} />;
  }

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        user={user} 
        points={points} 
        onLogoClick={() => setCurrentView('HOME')} 
        onProfileClick={() => setCurrentView('DASHBOARD')}
        onMoodboardClick={() => setCurrentView('MOODBOARD')}
        onLogout={handleLogout}
      />

      <main className="flex-grow pt-20 px-4 md:px-8">
        {currentView === 'HOME' && (
          <div className="max-w-7xl mx-auto">
            <CategoryBar 
              selected={selectedCategory} 
              onSelect={(cat) => setSelectedCategory(cat)} 
            />
            <PinterestFeed 
              materials={MOCK_MATERIALS.filter(m => !selectedCategory || m.category === selectedCategory)} 
              onSelect={navigateToDetails}
            />
          </div>
        )}

        {currentView === 'DETAILS' && selectedMaterial && (
          <MaterialDetail 
            material={selectedMaterial} 
            user={user}
            onBack={() => setCurrentView('HOME')}
            onDeductPoints={(amt) => setPoints(p => p - amt)}
          />
        )}

        {currentView === 'MOODBOARD' && (
          <MoodBoardDesigner 
            user={user}
            materials={MOCK_MATERIALS}
            onDeductPoints={(amt) => setPoints(p => p - amt)}
          />
        )}

        {currentView === 'DASHBOARD' && (
          user.role === 'DESIGNER' 
            ? <DesignerDashboard user={user} />
            : <SupplierDashboard user={user} />
        )}
      </main>

      <footer className="bg-white border-t py-6 text-center text-sm text-gray-500">
        &copy; 2024 MateriLib Premium Material Library. All Rights Reserved.
      </footer>
    </div>
  );
};

export default App;

