import React, { useState } from 'react';
import { Material, User } from '../types';

interface MaterialDetailProps {
  material: Material;
  user: User;
  onBack: () => void;
  onDeductPoints: (amt: number) => void;
}

const MaterialDetail: React.FC<MaterialDetailProps> = ({ material, user, onBack, onDeductPoints }) => {
  const [selectedColor, setSelectedColor] = useState(material.colors[0]);
  const [isQuoting, setIsQuoting] = useState(false);
  const [quoteForm, setQuoteForm] = useState({ project: '', address: '', area: '', date: '' });

  const handleSampleOrder = () => {
    if (confirm(`确认使用 ${material.pointsNeeded.sample} 点数购买小样？`)) {
      onDeductPoints(material.pointsNeeded.sample);
      alert('小样订单已提交！请前往控制台查看。');
    }
  };

  const handleQuoteSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    alert('报价申请已提交！材料商将尽快联系您。');
    setIsQuoting(false);
  };

  return (
    <div className="max-w-6xl mx-auto py-8">
      <button 
        onClick={onBack}
        className="mb-6 flex items-center gap-2 text-gray-500 hover:text-black transition-colors"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
        </svg>
        返回列表
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
        {/* Left: Info */}
        <div className="lg:col-span-5 flex flex-col gap-8">
          <div className="relative group">
            <img 
              src={material.image} 
              alt={material.name} 
              className="w-full aspect-[4/5] object-cover rounded-2xl shadow-lg border border-gray-200" 
              style={{ filter: `drop-shadow(0 0 10px ${selectedColor}44)` }}
            />
            <div className="absolute bottom-4 left-4 right-4 flex gap-2">
              {material.colors.map(c => (
                <button 
                  key={c}
                  onClick={() => setSelectedColor(c)}
                  className={`w-8 h-8 rounded-full border-2 transition-transform ${selectedColor === c ? 'scale-110 border-black' : 'border-white'}`}
                  style={{ backgroundColor: c }}
                />
              ))}
            </div>
          </div>

          <div className="space-y-6">
            <div>
              <h1 className="text-3xl font-bold mb-1">{material.name}</h1>
              <p className="text-gray-500 font-medium">{material.brand} · {material.category}</p>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="bg-gray-50 p-3 rounded-xl border border-gray-100">
                <span className="text-[10px] text-gray-400 font-bold uppercase block mb-1">规格尺寸</span>
                <span className="text-sm font-semibold">{material.specifications}</span>
              </div>
              <div className="bg-gray-50 p-3 rounded-xl border border-gray-100">
                <span className="text-[10px] text-gray-400 font-bold uppercase block mb-1">价格区间</span>
                <span className="text-sm font-semibold">{material.priceRange}</span>
              </div>
              <div className="bg-gray-50 p-3 rounded-xl border border-gray-100">
                <span className="text-[10px] text-gray-400 font-bold uppercase block mb-1">防火等级</span>
                <span className="text-sm font-semibold">{material.fireRating}</span>
              </div>
              <div className="bg-gray-50 p-3 rounded-xl border border-gray-100">
                <span className="text-[10px] text-gray-400 font-bold uppercase block mb-1">库存/周期</span>
                <span className="text-sm font-semibold">{material.stock ? '现货' : '定制'} · {material.leadTime}</span>
              </div>
            </div>

            <div className="flex gap-4">
              <button 
                onClick={handleSampleOrder}
                className="flex-1 bg-black text-white py-4 rounded-2xl font-bold hover:bg-gray-800 transition-colors shadow-lg shadow-black/10"
              >
                申领小样 (10点)
              </button>
              <button 
                onClick={() => setIsQuoting(true)}
                className="flex-1 border-2 border-black py-4 rounded-2xl font-bold hover:bg-gray-50 transition-colors"
              >
                申请报价
              </button>
            </div>
          </div>
        </div>

        {/* Right: Projects & Ratings */}
        <div className="lg:col-span-7 flex flex-col gap-8">
          <div>
            <h2 className="text-xl font-bold mb-4">应用案例</h2>
            <div className="flex flex-col gap-6 overflow-y-auto max-h-[600px] pr-4 custom-scrollbar">
              {material.projectPhotos.map((p, idx) => (
                <div key={idx} className="relative rounded-2xl overflow-hidden group">
                  <img src={p} className="w-full h-auto object-cover" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-6">
                    <div className="text-white">
                      <p className="font-bold text-lg">某高端住宅项目</p>
                      <p className="text-sm opacity-80">2023 · 上海浦东 · 350㎡</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100">
            <h2 className="text-lg font-bold mb-4">材料综合评估</h2>
            <div className="space-y-4">
              {Object.entries(material.ratings).map(([key, val]) => (
                <div key={key} className="flex items-center gap-4">
                  <span className="w-20 text-xs font-bold text-gray-500 uppercase">{key === 'aesthetic' ? '美观' : key === 'durable' ? '耐用' : key === 'service' ? '服务' : key === 'cleanliness' ? '易洁' : '推荐'}</span>
                  <div className="flex-1 h-2 bg-gray-200 rounded-full overflow-hidden">
                    <div className="h-full bg-black rounded-full" style={{ width: `${(val / 5) * 100}%` }}></div>
                  </div>
                  <span className="text-xs font-bold">{val}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Quote Dialog */}
      {isQuoting && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md p-8 rounded-3xl shadow-2xl">
            <h2 className="text-2xl font-bold mb-6">申请详细报价</h2>
            <form onSubmit={handleQuoteSubmit} className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">项目名称</label>
                <input required type="text" className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:border-black" />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">项目所在地</label>
                <input required type="text" className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:border-black" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-gray-400 uppercase mb-1">预估面积 (㎡)</label>
                  <input required type="number" className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:border-black" />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-400 uppercase mb-1">交付时间</label>
                  <input required type="date" className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:border-black" />
                </div>
              </div>
              <div className="pt-4 flex gap-4">
                <button type="button" onClick={() => setIsQuoting(false)} className="flex-1 py-3 text-gray-500 font-bold">取消</button>
                <button type="submit" className="flex-1 py-3 bg-black text-white rounded-xl font-bold shadow-lg shadow-black/20">提交申请</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default MaterialDetail;

import React, { useState } from 'react';
import { User, Material, MoodBoardItem } from '../types';

interface MoodBoardProps {
  user: User;
  materials: Material[];
  onDeductPoints: (amt: number) => void;
}

const MoodBoardDesigner: React.FC<MoodBoardProps> = ({ user, materials, onDeductPoints }) => {
  const [boardItems, setBoardItems] = useState<MoodBoardItem[]>([]);
  const [boardName, setBoardName] = useState('未命名材料板');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const addItem = (mat: Material) => {
    const newItem: MoodBoardItem = {
      id: Math.random().toString(36).substr(2, 9),
      materialId: mat.id,
      x: Math.random() * 400 + 100,
      y: Math.random() * 300 + 100,
      width: 200,
      height: 200,
      zIndex: boardItems.length + 1
    };
    setBoardItems([...boardItems, newItem]);
  };

  const handleExport = () => {
    if (confirm('确认消耗 20 点数生成并下载材料清单 Excel？')) {
      onDeductPoints(20);
      alert('材料清单已生成，正在启动下载...');
    }
  };

  const removeItem = (id: string) => {
    setBoardItems(boardItems.filter(i => i.id !== id));
  };

  return (
    <div className="flex h-[calc(100vh-120px)] bg-gray-50 rounded-3xl overflow-hidden border border-gray-200">
      {/* Sidebar: Material Library Selection */}
      <div className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-white border-r transition-all duration-300 flex flex-col`}>
        <div className="p-6 border-b flex justify-between items-center">
          <h3 className="font-bold">可选材料</h3>
          <button onClick={() => setIsSidebarOpen(false)} className="text-gray-400">✕</button>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {materials.map(mat => (
            <div 
              key={mat.id} 
              onClick={() => addItem(mat)}
              className="flex items-center gap-4 p-3 rounded-xl border border-transparent hover:border-black hover:bg-gray-50 cursor-pointer transition-all"
            >
              <img src={mat.image} className="w-12 h-12 rounded-lg object-cover" />
              <div>
                <p className="text-sm font-bold truncate w-40">{mat.name}</p>
                <p className="text-[10px] text-gray-400 uppercase font-bold">{mat.brand}</p>
              </div>
            </div>
          ))}
          <div className="p-4 bg-yellow-50 rounded-xl border border-yellow-100 mt-8">
            <p className="text-xs text-yellow-700 leading-relaxed font-medium">
              💡 点击左侧材料添加到画布。您可以自由拖拽位置和调整层级。
            </p>
          </div>
        </div>
      </div>

      {/* Main Canvas Area */}
      <div className="flex-1 relative flex flex-col">
        {/* Toolbar */}
        <div className="h-16 bg-white border-b flex items-center justify-between px-6 z-10 shadow-sm">
          {!isSidebarOpen && (
