            boardItems.map(item => {
              const mat = materials.find(m => m.id === item.materialId);
              return (
                <div 
                  key={item.id}
                  className="absolute p-2 bg-white shadow-xl rounded-lg cursor-move border border-gray-100 group"
                  style={{ left: item.x, top: item.y, width: item.width, zIndex: item.zIndex }}
