interface SupplierDashboardProps {
  user: User;
  onSubmitForReview: (material: PendingMaterial) => void;
}

const SupplierDashboard: React.FC<SupplierDashboardProps> = ({ user, onSubmitForReview }) => {
  const [isPublishing, setIsPublishing] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    category: Category.ST,
    brand: user.company || '',
    specifications: '',
    priceRange: '',
    stock: true,
    leadTime: '',
    fireRating: 'Class A',
    image: '',
    projectPhotos: [] as string[]
  });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, field: 'image' | 'projectPhotos') => {
    const files = e.target.files;
    if (!files) return;

    const fileArray = Array.from(files);
    const readers = fileArray.map(file => {
      return new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    });

    Promise.all(readers).then(results => {
      if (field === 'image') {
        setFormData(prev => ({ ...prev, image: results[0] }));
      } else {
        setFormData(prev => ({ ...prev, projectPhotos: [...prev.projectPhotos, ...results] }));
      }
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newPending: PendingMaterial = {
      ...formData,
      id: Math.random().toString(36).substr(2, 9),
