import React, { useState, useEffect } from 'react';
import { User, UserRole, Material, Category, MoodBoard, QuotationRequest, PendingMaterial } from './types';
import { MOCK_MATERIALS } from './constants';
import Navbar from './components/Navbar';
import Auth from './components/Auth';
import PinterestFeed from './components/PinterestFeed';
import CategoryBar from './components/CategoryBar';
import MaterialDetail from './components/MaterialDetail';
import MoodBoardDesigner from './components/MoodBoardDesigner';
import SupplierDashboard from './components/SupplierDashboard';
import DesignerDashboard from './components/DesignerDashboard';
import AdminDashboard from './components/AdminDashboard';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<'HOME' | 'DETAILS' | 'MOODBOARD' | 'DASHBOARD'>('HOME');
  const [selectedMaterial, setSelectedMaterial] = useState<Material | null>(null);
  const [selectedCategory, setSelectedCategory] = useState<Category | null>(null);
  const [points, setPoints] = useState(1000); // 1000 points for first 500 users

  // State for library and submissions
  const [library, setLibrary] = useState<Material[]>(MOCK_MATERIALS);
  const [pendingMaterials, setPendingMaterials] = useState<PendingMaterial[]>([]);

  // Navigation handlers
  const navigateToDetails = (material: Material) => {
    setSelectedMaterial(material);
    setCurrentView('DETAILS');
  };

  const handleAuthSuccess = (userData: User) => {
    setUser(userData);
    setPoints(userData.points);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentView('HOME');
  };

  // Review System Handlers
  const handleSubmitForReview = (newPending: PendingMaterial) => {
    setPendingMaterials(prev => [...prev, newPending]);
  };

  const handleApproveMaterial = (id: string) => {
    const materialToApprove = pendingMaterials.find(p => p.id === id);
    if (materialToApprove) {
      const newMaterial: Material = {
        ...materialToApprove,
        ratings: { aesthetic: 0, durable: 0, service: 0, cleanliness: 0, recommendation: 0 },
        pointsNeeded: { sample: 10, board: 20, export: 20 }
      };
      setLibrary(prev => [newMaterial, ...prev]);
      setPendingMaterials(prev => prev.filter(p => p.id !== id));
    }
  };

  const handleRejectMaterial = (id: string) => {
    setPendingMaterials(prev => prev.filter(p => p.id !== id));
  };

  if (!user) {
    return <Auth onAuthSuccess={handleAuthSuccess} />;
  }

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        user={user} 
        points={points} 
        onLogoClick={() => setCurrentView('HOME')} 
        onProfileClick={() => setCurrentView('DASHBOARD')}
        onMoodboardClick={() => setCurrentView('MOODBOARD')}
        onLogout={handleLogout}
      />

      <main className="flex-grow pt-20 px-4 md:px-8">
        {currentView === 'HOME' && (
          <div className="max-w-7xl mx-auto">
            <CategoryBar 
              selected={selectedCategory} 
              onSelect={(cat) => setSelectedCategory(cat)} 
            />
            <PinterestFeed 
              materials={library.filter(m => !selectedCategory || m.category === selectedCategory)} 
              onSelect={navigateToDetails}
            />
          </div>
        )}

        {currentView === 'DETAILS' && selectedMaterial && (
          <MaterialDetail 
            material={selectedMaterial} 
            user={user}
            onBack={() => setCurrentView('HOME')}
            onDeductPoints={(amt) => setPoints(p => p - amt)}
          />
        )}

        {currentView === 'MOODBOARD' && (
          <MoodBoardDesigner 
            user={user}
            materials={library}
            onDeductPoints={(amt) => setPoints(p => p - amt)}
          />
        )}

        {currentView === 'DASHBOARD' && (
          user.role === 'ADMIN' ? (
            <AdminDashboard 
              user={user} 
              pendingList={pendingMaterials}
              onApprove={handleApproveMaterial}
              onReject={handleRejectMaterial}
            />
          ) : (
            user.role === 'DESIGNER' 
              ? <DesignerDashboard user={user} />
              : <SupplierDashboard user={user} onSubmitForReview={handleSubmitForReview} />
          )
        )}
      </main>

      <footer className="bg-white border-t py-6 text-center text-sm text-gray-500">
        &copy; 2024 MateriLib Premium Material Library. All Rights Reserved.
        {user.role !== 'ADMIN' && (
          <button 
            onClick={() => setUser({...user, role: 'ADMIN'})}
            className="ml-4 text-[10px] text-gray-300 hover:text-black font-bold uppercase"
          >
            [平台管理员模式]
          </button>
        )}
      </footer>
    </div>
  );
};

export default App;

