    fireRating: 'Class A',
    image: '',
    projectPhotos: [] as string[]
  });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, field: 'image' | 'projectPhotos') => {
    const files = e.target.files;
    if (!files) return;

    // Fix: Explicitly cast Array.from result to File[] to avoid 'unknown' type inference
    const fileArray = Array.from(files) as File[];
    const readers = fileArray.map(file => {
      return new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    });

    Promise.all(readers).then(results => {
      if (field === 'image') {
        setFormData(prev => ({ ...prev, image: results[0] }));
      } else {
        setFormData(prev => ({ ...prev, projectPhotos: [...prev.projectPhotos, ...results] }));
      }
    });
  };

