import React, { useState, useRef, useEffect } from 'react';
import { User, Material, MoodBoardItem, Category } from '../types';

interface MoodBoardProps {
  user: User;
  materials: Material[];
  onDeductPoints: (amt: number) => void;
}

const MoodBoardDesigner: React.FC<MoodBoardProps> = ({ user, materials, onDeductPoints }) => {
  const [boardItems, setBoardItems] = useState<MoodBoardItem[]>([]);
  const [boardName, setBoardName] = useState('某某家装项目材料板');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [draggingItem, setDraggingItem] = useState<{ id: string; offsetX: number; offsetY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);

  const addItem = (mat: Material) => {
    const newItem: MoodBoardItem = {
      id: Math.random().toString(36).substr(2, 9),
      materialId: mat.id,
      x: 50 + Math.random() * 50,
      y: 50 + Math.random() * 50,
      width: 200,
      height: 200,
      zIndex: boardItems.length + 1
    };
    setBoardItems([...boardItems, newItem]);
  };

  const handleDragStart = (e: React.MouseEvent, id: string) => {
    const item = boardItems.find(i => i.id === id);
    if (!item) return;
    setDraggingItem({
      id,
      offsetX: e.clientX - item.x,
      offsetY: e.clientY - item.y
    });
    // Bring to front
    setBoardItems(prev => prev.map(i => i.id === id ? { ...i, zIndex: Math.max(...prev.map(x => x.zIndex)) + 1 } : i));
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!draggingItem) return;
    setBoardItems(prev => prev.map(item => 
      item.id === draggingItem.id 
        ? { ...item, x: e.clientX - draggingItem.offsetX, y: e.clientY - draggingItem.offsetY }
        : item
    ));
  };

  const handleMouseUp = () => {
    setDraggingItem(null);
  };

  const removeItem = (id: string) => {
    setBoardItems(boardItems.filter(i => i.id !== id));
  };

  const getCategoryPrefix = (cat: Category) => {
    const map: Record<string, string> = {
      [Category.ST]: 'ST',
      [Category.CT]: 'CT',
      [Category.CO]: 'CO',
      [Category.SF]: 'SF',
      [Category.WD]: 'WD',
      [Category.GL]: 'GL',
      [Category.MT]: 'MT',
      [Category.PVC]: 'PVC',
      [Category.FB]: 'FB',
      [Category.CP]: 'CP',
      [Category.L]: 'L',
      [Category.Other]: 'OT'
    };
    return map[cat] || 'MAT';
  };

  const exportExcel = () => {
    if (boardItems.length === 0) {
      alert('请先添加材料。');
      return;
    }
    if (confirm('确认消耗 20 点数生成并下载材料清单 Excel？')) {
      onDeductPoints(20);

      // Group materials to assign codes like CT01, CT02
      const counts: Record<string, number> = {};
      const rows = boardItems.map((item) => {
        const mat = materials.find(m => m.id === item.materialId);
        if (!mat) return null;
        const prefix = getCategoryPrefix(mat.category);
        counts[prefix] = (counts[prefix] || 0) + 1;
        const code = `${prefix}${String(counts[prefix]).padStart(2, '0')}`;

        return {
          code,
          name: mat.name,
          pos: '见图纸',
          specs: mat.specifications,
          tech: `防火等级: ${mat.fireRating}; 周期: ${mat.leadTime}`,
          req: '需审核样块',
          notes: '所有样品需业主与设计方审核后方可采购',
          price: mat.priceRange,
          brand: mat.brand
        };
      }).filter(Boolean);

      // Create CSV content (Excel compatible UTF-8 with BOM)
      const headers = ['编号', '名称', '使用位置', '尺寸/型号', '技术要求', '送样要求', '备注', '价格', '材料商'];
      const csvContent = "\uFEFF" + [
        headers.join(','),
        ...rows.map(r => r ? [r.code, r.name, r.pos, `"${r.specs}"`, `"${r.tech}"`, r.req, r.notes, `"${r.price}"`, r.brand].join(',') : '')
      ].join('\n');

      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement("a");
      const url = URL.createObjectURL(blob);
      link.setAttribute("href", url);
      link.setAttribute("download", `${boardName}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    <div className="flex h-[calc(100vh-120px)] bg-gray-50 rounded-3xl overflow-hidden border border-gray-200 shadow-sm">
      {/* Sidebar */}
      <div className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-white border-r transition-all duration-300 flex flex-col`}>
        <div className="p-6 border-b flex justify-between items-center">
          <h3 className="font-bold text-gray-900">材料库选择</h3>
          <button onClick={() => setIsSidebarOpen(false)} className="text-gray-400 hover:text-black">✕</button>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-4 no-scrollbar">
          {materials.map(mat => (
            <div 
              key={mat.id} 
              onClick={() => addItem(mat)}
              className="flex items-center gap-4 p-3 rounded-2xl border border-transparent hover:border-black hover:bg-gray-50 cursor-pointer transition-all group"
            >
              <img src={mat.image} className="w-14 h-14 rounded-xl object-cover shadow-sm group-hover:scale-105 transition-transform" />
              <div>
                <p className="text-sm font-bold text-gray-800 truncate w-36">{mat.name}</p>
                <p className="text-[10px] text-gray-400 uppercase font-bold tracking-tight">{mat.brand}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Canvas */}
      <div 
        className="flex-1 relative flex flex-col select-none"
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
      >
        <div className="h-16 bg-white border-b flex items-center justify-between px-8 z-10 shadow-sm">
          <div className="flex items-center gap-4">
            {!isSidebarOpen && (
              <button onClick={() => setIsSidebarOpen(true)} className="text-gray-400 hover:text-black p-2">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                </svg>
              </button>
            )}
            <input 
              value={boardName}
              onChange={(e) => setBoardName(e.target.value)}
              className="text-lg font-bold outline-none border-none bg-transparent focus:ring-0 w-64"
            />
          </div>
          <div className="flex gap-4">
            <button className="text-sm font-bold text-gray-400 hover:text-black transition-colors">草稿箱</button>
            <button 
              onClick={exportExcel}
              className="bg-black text-white px-8 py-2.5 rounded-full text-sm font-bold shadow-lg shadow-black/10 hover:bg-gray-800 transition-all active:scale-95"
            >
              生成材料表 (20点)
            </button>
          </div>
        </div>

        <div className="flex-1 relative moodboard-canvas overflow-auto p-20" ref={canvasRef}>
          {boardItems.length === 0 ? (
            <div className="absolute inset-0 flex items-center justify-center text-gray-300 font-medium">
              点击左侧材料开始创作您的 Mood Board
            </div>
          ) : (
            boardItems.map(item => {
              const mat = materials.find(m => m.id === item.materialId);
              return (
                <div 
                  key={item.id}
                  className={`absolute cursor-move group transition-shadow ${draggingItem?.id === item.id ? 'z-[1000] scale-[1.02]' : ''}`}
                  style={{ 
                    left: item.x, 
                    top: item.y, 
                    width: item.width, 
                    zIndex: item.zIndex
                  }}
                  onMouseDown={(e) => handleDragStart(e, item.id)}
                >
                  <img src={mat?.image} className="w-full h-auto rounded-md shadow-lg pointer-events-none transition-all group-hover:shadow-2xl" />
                  <div className="mt-3 opacity-0 group-hover:opacity-100 transition-opacity flex justify-between items-center bg-white/80 backdrop-blur-sm p-2 rounded-lg shadow-sm border border-gray-100">
                    <div className="text-[10px] font-bold">
                      <p className="truncate text-gray-900">{mat?.name}</p>
                      <p className="text-gray-400 uppercase tracking-tighter">{mat?.brand}</p>
                    </div>
                    <button 
                      onClick={(e) => { e.stopPropagation(); removeItem(item.id); }}
                      className="bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-[10px] hover:bg-red-600 shadow-md"
                    >
                      ✕
                    </button>
                  </div>
                </div>
              )
            })
          )}
        </div>
      </div>
    </div>
  );
};

export default MoodBoardDesigner;

