const MoodBoardDesigner: React.FC<MoodBoardProps> = ({ user, materials, onDeductPoints }) => {
  const [boardItems, setBoardItems] = useState<MoodBoardItem[]>([]);
  const [boardName, setBoardName] = useState('深圳小巨蛋保利剧院项目材料板');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [draggingItem, setDraggingItem] = useState<{ id: string; offsetX: number; offsetY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);

  const addItem = (mat: Material) => {
    const newItem: MoodBoardItem = {
      id: Math.random().toString(36).substr(2, 9),
      materialId: mat.id,
      x: 100 + Math.random() * 50,
      y: 100 + Math.random() * 50,
      width: 220,
      height: 220,
      zIndex: boardItems.length + 1
    };
    setBoardItems([...boardItems, newItem]);
  };

  const handleDragStart = (e: React.MouseEvent, id: string) => {
    const item = boardItems.find(i => i.id === id);
    if (!item || !canvasRef.current) return;

    const rect = canvasRef.current.getBoundingClientRect();
    setDraggingItem({
      id,
      offsetX: e.clientX - rect.left - item.x,
      offsetY: e.clientY - rect.top - item.y
    });

    // Bring to front
    setBoardItems(prev => prev.map(i => 
      i.id === id ? { ...i, zIndex: Math.max(...prev.map(x => x.zIndex), 0) + 1 } : i
    ));
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!draggingItem || !canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();

    const newX = e.clientX - rect.left - draggingItem.offsetX;
    const newY = e.clientY - rect.top - draggingItem.offsetY;

    setBoardItems(prev => prev.map(item => 
      item.id === draggingItem.id 
        ? { ...item, x: newX, y: newY }
        : item
    ));
  };

  const handleMouseUp = () => {
    setDraggingItem(null);
  };

  const removeItem = (id: string) => {
    setBoardItems(boardItems.filter(i => i.id !== id));
  };

  const getCategoryPrefix = (cat: Category) => {
    const map: Record<string, string> = {
      [Category.ST]: 'ST',
      [Category.CT]: 'CT',
      [Category.CO]: 'CO',
      [Category.SF]: 'SF',
      [Category.WD]: 'WD',
      [Category.GL]: 'GL',
      [Category.MT]: 'MT',
      [Category.PVC]: 'PVC',
      [Category.FB]: 'FB',
      [Category.CP]: 'CP',
      [Category.L]: 'L',
      [Category.Other]: 'Other'
    };
    return map[cat] || 'MAT';
  };

  const exportExcel = () => {
    if (boardItems.length === 0) {
      alert('请先添加材料到板中。');
      return;
    }
    if (confirm('确认消耗 20 点数生成并下载材料清单 Excel (CSV)？')) {
      onDeductPoints(20);

      const categoryCounts: Record<string, number> = {};
      const rows = boardItems.map(item => {
        const mat = materials.find(m => m.id === item.materialId);
        if (!mat) return null;

        const prefix = getCategoryPrefix(mat.category);
        categoryCounts[prefix] = (categoryCounts[prefix] || 0) + 1;
        const code = `${prefix}-${categoryCounts[prefix]}`;

        return {
          code,
          name: mat.name,
          pos: '见图纸',
          imgUrl: mat.image,
          surface: mat.colors[0] || '默认',
          size: mat.specifications,
          tech: `防火等级:${mat.fireRating}; 周期:${mat.leadTime}`,
          sample: '乙方需提供小样',
          notes: '所有样品需业主与设计方审核后方可采购',
          price: mat.priceRange,
          contact: mat.brand
        };
      }).filter(Boolean);

      // Create CSV with BOM for Excel compatibility
      const headers = ['编号', '名称', '使用位置', '图片链接', '颜色/表面处理', '尺寸/型号', '技术要求', '送样要求', '备注', '价格', '材料商联系方式'];
      const csvContent = "\uFEFF" + [
        headers.join(','),
        ...rows.map(r => r ? [
          r.code, 
          r.name, 
          r.pos, 
          r.imgUrl, 
          r.surface, 
          `"${r.size}"`, 
          `"${r.tech}"`, 
          r.sample, 
          `"${r.notes}"`, 
          `"${r.price}"`, 
          r.contact
        ].join(',') : '')
      ].join('\n');

      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement("a");
      const url = URL.createObjectURL(blob);
      link.setAttribute("href", url);
      link.setAttribute("download", `${boardName}_材料表.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    <div className="flex h-[calc(100vh-120px)] bg-gray-100 rounded-3xl overflow-hidden border border-gray-200 shadow-inner">
      {/* Sidebar */}
      <div className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-white border-r transition-all duration-300 flex flex-col`}>
        <div className="p-6 border-b flex justify-between items-center bg-gray-50/50">
          <h3 className="font-bold text-gray-900">材料资产</h3>
          <button onClick={() => setIsSidebarOpen(false)} className="text-gray-400 hover:text-black p-2 rounded-full hover:bg-gray-100 transition-colors">✕</button>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-4 no-scrollbar">
          {materials.map(mat => (
            <div 
              key={mat.id} 
              onClick={() => addItem(mat)}
              className="flex items-center gap-4 p-2 rounded-2xl border border-transparent hover:border-black hover:bg-white cursor-pointer transition-all group shadow-sm hover:shadow-md"
            >
              <img src={mat.image} className="w-16 h-16 rounded-xl object-cover grayscale-[0.2] group-hover:grayscale-0 transition-all" />
              <div>
                <p className="text-sm font-bold text-gray-800 truncate w-36">{mat.name}</p>
                <p className="text-[10px] text-gray-400 uppercase font-black tracking-widest">{mat.brand}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Canvas Area */}
      <div 
        className="flex-1 relative flex flex-col select-none overflow-hidden"
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        {/* Toolbar */}
        <div className="h-16 bg-white/80 backdrop-blur-md border-b flex items-center justify-between px-8 z-20 shadow-sm">
          <div className="flex items-center gap-4">
            {!isSidebarOpen && (
              <button onClick={() => setIsSidebarOpen(true)} className="text-gray-400 hover:text-black p-2 rounded-full hover:bg-gray-100">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                </svg>
              </button>
            )}
            <input 
              value={boardName}
              onChange={(e) => setBoardName(e.target.value)}
              className="text-lg font-black outline-none border-none bg-transparent focus:ring-0 w-80 tracking-tight"
            />
          </div>
          <div className="flex gap-4">
            <button className="text-xs font-black text-gray-400 hover:text-black uppercase tracking-widest transition-colors">草稿自动保存</button>
            <button 
              onClick={exportExcel}
              className="bg-black text-white px-8 py-2.5 rounded-full text-sm font-black shadow-xl shadow-black/20 hover:scale-[1.02] active:scale-[0.98] transition-all"
            >
              一键生成材料表 (20点)
            </button>
          </div>
        </div>

        {/* The Grid / Canvas */}
        <div 
          className="flex-1 relative moodboard-canvas overflow-auto p-40" 
          ref={canvasRef}
        >
          {boardItems.length === 0 ? (
            <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-300 pointer-events-none">
              <span className="text-6xl mb-4">🎨</span>
              <p className="font-bold uppercase tracking-widest text-xs">点击左侧列表添加材料进行排版</p>
            </div>
          ) : (
            boardItems.map(item => {
              const mat = materials.find(m => m.id === item.materialId);
              return (
                <div 
                  key={item.id}
                  className={`absolute cursor-move group transition-shadow ${draggingItem?.id === item.id ? 'z-[1000] scale-[1.02] shadow-2xl' : ''}`}
                  style={{ 
                    left: item.x, 
                    top: item.y, 
                    width: item.width, 
                    zIndex: item.zIndex
                  }}
                  onMouseDown={(e) => handleDragStart(e, item.id)}
                >
                  {/* Removed white border/box as requested */}
                  <img src={mat?.image} className="w-full h-auto rounded shadow-xl pointer-events-none group-hover:shadow-2xl transition-all" />

                  {/* Controls visible on hover */}
                  <div className="absolute -top-3 -right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button 
                      onClick={(e) => { e.stopPropagation(); removeItem(item.id); }}
                      className="bg-red-500 text-white rounded-full w-8 h-8 flex items-center justify-center text-sm font-bold shadow-lg hover:bg-red-600 active:scale-90"
                    >
                      ✕
                    </button>
                  </div>

                  {/* Item Label on hover */}
                  <div className="absolute -bottom-10 left-0 right-0 text-center opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                    <span className="bg-black/80 text-white text-[10px] font-black uppercase px-3 py-1 rounded-full backdrop-blur-sm">
                      {getCategoryPrefix(mat?.category || Category.Other)}-{mat?.name}
                    </span>
                  </div>
                </div>
              )
            })
          )}
        </div>
      </div>
    </div>
  );
};

export default MoodBoardDesigner;

