import React, { useState, useEffect } from 'react';
import { User, UserRole, Material, Category, MoodBoard, PointTransaction, PendingMaterial } from './types';
import { MOCK_MATERIALS } from './constants';
import Navbar from './components/Navbar';
import Auth from './components/Auth';
import PinterestFeed from './components/PinterestFeed';
import CategoryBar from './components/CategoryBar';
import MaterialDetail from './components/MaterialDetail';
import MoodBoardDesigner from './components/MoodBoardDesigner';
import SupplierDashboard from './components/SupplierDashboard';
import DesignerDashboard from './components/DesignerDashboard';
import AdminDashboard from './components/AdminDashboard';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<'HOME' | 'DETAILS' | 'MOODBOARD' | 'DASHBOARD'>('HOME');
  const [selectedMaterial, setSelectedMaterial] = useState<Material | null>(null);
  const [selectedCategory, setSelectedCategory] = useState<Category | null>(null);
  const [points, setPoints] = useState(1000); 
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPass, setAdminPass] = useState('');

  // States
  const [library, setLibrary] = useState<Material[]>(MOCK_MATERIALS);
  const [pendingMaterials, setPendingMaterials] = useState<PendingMaterial[]>([]);
  const [moodboards, setMoodboards] = useState<MoodBoard[]>([
    { id: 'mb_1', name: '默认情绪板', items: [], isPaid: false, maxMaterials: 10 }
  ]);
  const [activeMoodboardId, setActiveMoodboardId] = useState<string>('mb_1');
  const [savedMaterialIds, setSavedMaterialIds] = useState<string[]>([]);

  const handleAuthSuccess = (userData: User) => {
    setUser({ ...userData, transactions: [] });
    setPoints(userData.points);
  };

  const handleAdminAuth = () => {
    if (adminPass === 'admin123') {
      setUser({
        id: 'admin_1',
        name: '平台管理员',
        email: 'admin@materialmatters.com',
        role: 'ADMIN',
        points: 999999
      });
      setShowAdminLogin(false);
      setAdminPass('');
      setCurrentView('DASHBOARD');
    } else {
      alert('密码错误');
    }
  };

  const handleSaveMaterial = (matId: string) => {
    setSavedMaterialIds(prev => {
      const isSaved = prev.includes(matId);
      const newSaved = isSaved ? prev.filter(id => id !== matId) : [...prev, matId];
      // Update library counts for UI simulation
      setLibrary(prevLib => prevLib.map(m => 
        m.id === matId ? { ...m, saves: isSaved ? m.saves - 1 : m.saves + 1 } : m
      ));
      return newSaved;
    });
  };

  const handlePointChange = (amount: number, desc: string) => {
    setPoints(p => p + amount);
    if (user) {
      const newTransaction: PointTransaction = {
        id: Math.random().toString(),
        amount,
        date: new Date().toISOString(),
        description: desc
      };
      setUser({ ...user, transactions: [...(user.transactions || []), newTransaction] });
    }
  };

  if (!user) {
    return <Auth onAuthSuccess={handleAuthSuccess} />;
  }

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        user={user} 
        points={points} 
        onLogoClick={() => setCurrentView('HOME')} 
        onProfileClick={() => setCurrentView('DASHBOARD')}
        onMoodboardClick={() => setCurrentView('MOODBOARD')}
        onLogout={() => setUser(null)}
      />

      <main className="flex-grow pt-20 px-4 md:px-8">
        {currentView === 'HOME' && (
          <div className="max-w-7xl mx-auto">
            <CategoryBar 
              selected={selectedCategory} 
              onSelect={setSelectedCategory} 
            />
            <PinterestFeed 
              materials={library.filter(m => !selectedCategory || m.category === selectedCategory)} 
              onSelect={(m) => { setSelectedMaterial(m); setCurrentView('DETAILS'); }}
              onSave={handleSaveMaterial}
              savedIds={savedMaterialIds}
            />
          </div>
        )}

        {currentView === 'DETAILS' && selectedMaterial && (
          <MaterialDetail 
            material={selectedMaterial} 
            user={user}
            onBack={() => setCurrentView('HOME')}
            onDeductPoints={(amt) => handlePointChange(-amt, '申领材料小样')}
          />
        )}

        {currentView === 'MOODBOARD' && (
          <MoodBoardDesigner 
            user={user}
            points={points}
            materials={library}
            moodboards={moodboards}
            setMoodboards={setMoodboards}
            activeMoodboardId={activeMoodboardId}
            setActiveMoodboardId={setActiveMoodboardId}
            onDeductPoints={(amt, desc) => handlePointChange(-amt, desc)}
          />
        )}

        {currentView === 'DASHBOARD' && (
          user.role === 'ADMIN' ? (
            <AdminDashboard 
              user={user} 
              library={library}
              setLibrary={setLibrary}
              pendingList={pendingMaterials}
              onApprove={(id) => {}} // Integration logic
            />
          ) : (
            user.role === 'DESIGNER' 
              ? <DesignerDashboard user={user} savedIds={savedMaterialIds} setSavedIds={setSavedMaterialIds} moodboards={moodboards} library={library} />
              : <SupplierDashboard user={user} onSubmitForReview={() => {}} />
          )
        )}
      </main>

      {/* Admin Key Entry */}
      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50">
        <button 
          onClick={() => setShowAdminLogin(true)}
          className="bg-black/10 hover:bg-black/20 p-2 rounded-full backdrop-blur-sm transition-all text-black/30 hover:text-black/60"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" />
          </svg>
        </button>
      </div>

      {showAdminLogin && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[40px] w-full max-w-sm shadow-2xl">
            <h3 className="text-2xl font-black mb-6">运营控制中心</h3>
            <input 
              type="password" 
              placeholder="请输入管理员访问密码"
              className="w-full p-4 bg-gray-50 rounded-2xl mb-4 border-none outline-none focus:ring-2 focus:ring-black"
              value={adminPass}
              onChange={(e) => setAdminPass(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleAdminAuth()}
            />
            <div className="flex gap-4">
              <button onClick={() => setShowAdminLogin(false)} className="flex-1 py-4 font-bold text-gray-400">取消</button>
              <button onClick={handleAdminAuth} className="flex-1 py-4 bg-black text-white rounded-2xl font-bold">进入后台</button>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white border-t py-6 text-center text-sm text-gray-500">
        &copy; 2024 MATERIAL MATTERS. All Rights Reserved.
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { User, Material, MoodBoard, MoodBoardItem, Category } from '../types';

interface MoodBoardProps {
  user: User;
  points: number;
  materials: Material[];
  moodboards: MoodBoard[];
  setMoodboards: React.Dispatch<React.SetStateAction<MoodBoard[]>>;
  activeMoodboardId: string;
  setActiveMoodboardId: (id: string) => void;
  onDeductPoints: (amt: number, desc: string) => void;
}

const MoodBoardDesigner: React.FC<MoodBoardProps> = ({ 
  user, points, materials, moodboards, setMoodboards, 
  activeMoodboardId, setActiveMoodboardId, onDeductPoints 
}) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [resizingItem, setResizingItem] = useState<{ id: string; startWidth: number; startHeight: number; startX: number; startY: number } | null>(null);
  const [draggingItem, setDraggingItem] = useState<{ id: string; offsetX: number; offsetY: number } | null>(null);
  const canvasRef = useRef<HTMLDivElement>(null);

  const activeBoard = moodboards.find(b => b.id === activeMoodboardId) || moodboards[0];

  const handleCreateBoard = () => {
    const freeBoards = moodboards.filter(b => !b.isPaid).length;
    let newBoard: MoodBoard;

    if (freeBoards < 3) {
      newBoard = { id: `mb_${Date.now()}`, name: `新建情绪板 ${moodboards.length + 1}`, items: [], isPaid: false, maxMaterials: 10 };
    } else {
      if (confirm('免费情绪板已达上限(3个)。是否消耗 50 积分创建一个高级情绪板？(限额20款材料)')) {
        if (points < 50) return alert('积分不足');
        onDeductPoints(50, '创建高级情绪板');
        newBoard = { id: `mb_${Date.now()}`, name: `高级情绪板 ${moodboards.length + 1}`, items: [], isPaid: true, maxMaterials: 20 };
      } else return;
    }
    setMoodboards([...moodboards, newBoard]);
    setActiveMoodboardId(newBoard.id);
  };

  const addItem = (mat: Material) => {
    if (activeBoard.items.length >= activeBoard.maxMaterials) {
      return alert(`当前情绪板材料已达上限 (${activeBoard.maxMaterials}款)`);
    }
    const newItem: MoodBoardItem = {
      id: Math.random().toString(36).substr(2, 9),
      materialId: mat.id,
      x: 100, y: 100, width: 200, height: 200, zIndex: activeBoard.items.length + 1
    };
    updateBoardItems([...activeBoard.items, newItem]);
  };

  const updateBoardItems = (items: MoodBoardItem[]) => {
    setMoodboards(prev => prev.map(b => b.id === activeMoodboardId ? { ...b, items } : b));
  };

  const handleMouseDown = (e: React.MouseEvent, id: string, type: 'move' | 'resize') => {
    const item = activeBoard.items.find(i => i.id === id);
    if (!item || !canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();

    if (type === 'resize') {
      setResizingItem({ id, startWidth: item.width, startHeight: item.height, startX: e.clientX, startY: e.clientY });
    } else {
      setDraggingItem({ id, offsetX: e.clientX - rect.left - item.x, offsetY: e.clientY - rect.top - item.y });
    }
    // Bring to front
    updateBoardItems(activeBoard.items.map(i => i.id === id ? { ...i, zIndex: Math.max(...activeBoard.items.map(x => x.zIndex)) + 1 } : i));
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (resizingItem) {
      const deltaX = e.clientX - resizingItem.startX;
      const scale = (resizingItem.startWidth + deltaX) / resizingItem.startWidth;
      updateBoardItems(activeBoard.items.map(i => i.id === resizingItem.id ? { 
        ...i, 
        width: Math.max(50, resizingItem.startWidth + deltaX),
        height: Math.max(50, resizingItem.startHeight * scale) 
      } : i));
    } else if (draggingItem && canvasRef.current) {
      const rect = canvasRef.current.getBoundingClientRect();
      updateBoardItems(activeBoard.items.map(i => i.id === draggingItem.id ? { 
        ...i, 
        x: e.clientX - rect.left - draggingItem.offsetX, 
        y: e.clientY - rect.top - draggingItem.offsetY 
      } : i));
    }
  };

  const handleExport = () => {
    if (confirm('确认消耗 20 点数生成该项目的材料清单？')) {
      onDeductPoints(20, `生成材料表: ${activeBoard.name}`);
      alert('已生成 CSV 材料清单，正在开始下载...');
    }
  };

  return (
    <div className="flex h-[calc(100vh-120px)] bg-gray-50 rounded-3xl overflow-hidden border border-gray-200" onMouseMove={handleMouseMove} onMouseUp={() => { setDraggingItem(null); setResizingItem(null); }}>
      {/* Sidebar */}
      <div className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-white border-r transition-all duration-300 flex flex-col`}>
