                <span>{mb.name}</span>
                <span className="opacity-50 text-[9px]">{mb.items.length}/{mb.maxMaterials}</span>
              </button>
            ))}
          </div>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          <h3 className="text-[10px] font-black uppercase text-gray-400 tracking-widest px-2">添加材料</h3>
          {materials.map(mat => (
            <div key={mat.id} onClick={() => addItem(mat)} className="flex items-center gap-4 p-2 rounded-xl hover:bg-gray-50 cursor-pointer group">
              <img src={mat.image} className="w-12 h-12 rounded-lg object-cover" />
              <div className="flex-1 min-w-0">
