        <div className="flex-1 relative moodboard-canvas overflow-auto" ref={canvasRef}>
          {activeBoard.items.map(item => {
            const mat = materials.find(m => m.id === item.materialId);
            return (
              <div 
                key={item.id} 
                className="absolute group"
                style={{ left: item.x, top: item.y, width: item.width, zIndex: item.zIndex }}
              >
                <div onMouseDown={(e) => handleMouseDown(e, item.id, 'move')}>
                  <img src={mat?.image} className="w-full h-auto rounded-lg shadow-xl cursor-move pointer-events-none" />
                </div>
                {/* Resize Handle */}
                <div 
                  onMouseDown={(e) => handleMouseDown(e, item.id, 'resize')}
                  className="absolute bottom-0 right-0 w-6 h-6 bg-black text-white rounded-tl-lg rounded-br-lg flex items-center justify-center cursor-nwse-resize opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <svg className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M3 10a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" /></svg>
                </div>
                <button 
                  onClick={() => updateBoardItems(activeBoard.items.filter(i => i.id !== item.id))}
                  className="absolute -top-3 -right-3 w-6 h-6 bg-red-500 text-white rounded-full opacity-0 group-hover:opacity-100 flex items-center justify-center text-[10px] shadow-lg"
                >✕</button>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

