import React, { useState } from 'react';
import { User, Material, Category, MoodBoard } from '../types';

interface DashboardProps {
  user: User;
  savedIds: string[];
  setSavedIds: React.Dispatch<React.SetStateAction<string[]>>;
  moodboards: MoodBoard[];
  library: Material[];
}

const DesignerDashboard: React.FC<DashboardProps> = ({ user, savedIds, setSavedIds, moodboards, library }) => {
  const [activeTab, setActiveTab] = useState<'TABLES' | 'ASSETS'>('TABLES');
  const [expandedCategory, setExpandedCategory] = useState<Category | null>(null);

  const savedMaterials = library.filter(m => savedIds.includes(m.id));
  const groupedAssets = Object.values(Category).map(cat => ({
    category: cat,
    items: savedMaterials.filter(m => m.category === cat)
  }));

  const handleRemoveAsset = (id: string) => {
    setSavedIds(prev => prev.filter(mid => mid !== id));
  };

  return (
    <div className="max-w-6xl mx-auto py-10 space-y-12">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black mb-2 tracking-tighter">控制中心</h1>
          <p className="text-gray-500 font-medium">{user.name} · {user.company}</p>
        </div>
        <div className="flex gap-4">
          <div className="bg-white p-6 rounded-[32px] border text-center shadow-sm">
            <p className="text-[10px] font-black uppercase text-gray-400 mb-1">可用积分</p>
            <p className="text-2xl font-black">{user.points}</p>
          </div>
        </div>
      </header>

      <div className="flex gap-8 border-b">
        <button onClick={() => setActiveTab('TABLES')} className={`pb-4 text-sm font-black uppercase tracking-widest transition-all ${activeTab === 'TABLES' ? 'border-b-4 border-black text-black' : 'text-gray-300'}`}>我的材料表</button>
        <button onClick={() => setActiveTab('ASSETS')} className={`pb-4 text-sm font-black uppercase tracking-widest transition-all ${activeTab === 'ASSETS' ? 'border-b-4 border-black text-black' : 'text-gray-300'}`}>材料资产管理</button>
      </div>

      {activeTab === 'TABLES' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {moodboards.map(mb => (
            <div key={mb.id} className="bg-white p-8 rounded-[40px] border border-gray-100 shadow-sm hover:shadow-xl transition-all cursor-pointer group">
              <div className="flex justify-between items-start mb-6">
                <div>
                  <h3 className="text-xl font-bold">{mb.name}</h3>
                  <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-1">项目材料清单</p>
                </div>
                {mb.isPaid && <span className="bg-yellow-400 text-black text-[9px] font-black px-2 py-0.5 rounded-full">PRO</span>}
              </div>
              <div className="space-y-4 mb-8">
                {mb.items.slice(0, 3).map((item, idx) => {
                  const m = library.find(x => x.id === item.materialId);
                  return (
                    <div key={idx} className="flex items-center justify-between text-xs">
                       <span className="font-bold text-gray-600 truncate flex-1 mr-4">{m?.name}</span>
                       <span className="font-black text-gray-400">¥ {m?.priceRange.split('-')[0].replace('¥','')}+</span>
                    </div>
                  );
                })}
                {mb.items.length > 3 && <p className="text-[10px] text-gray-300 italic">以及其他 {mb.items.length - 3} 款材料...</p>}
                {mb.items.length === 0 && <p className="text-xs text-gray-300 italic py-4">该清单暂无材料</p>}
              </div>
              <button className="w-full bg-gray-50 text-black py-4 rounded-2xl font-bold text-xs group-hover:bg-black group-hover:text-white transition-all">查看详细报价表</button>
            </div>
          ))}
        </div>
      )}

      {activeTab === 'ASSETS' && (
        <div className="space-y-4">
          {groupedAssets.map(group => (
            <div key={group.category} className="bg-white rounded-[32px] border border-gray-100 overflow-hidden">
              <button 
                onClick={() => setExpandedCategory(expandedCategory === group.category ? null : group.category)}
                className="w-full flex items-center justify-between p-6 hover:bg-gray-50 transition-colors"
              >
                <div className="flex items-center gap-4">
                  <span className="text-xl">{group.items.length > 0 ? '📁' : '📁'}</span>
                  <span className="font-bold text-lg">{group.category} <span className="text-gray-300 ml-2 font-black">({group.items.length})</span></span>
                </div>
                <span className={`transition-transform ${expandedCategory === group.category ? 'rotate-180' : ''}`}>▼</span>
              </button>

              {expandedCategory === group.category && (
                <div className="p-6 pt-0 grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 gap-4">
                  {group.items.map(item => (
                    <div key={item.id} className="relative group aspect-square rounded-2xl overflow-hidden border">
                      <img src={item.image} className="w-full h-full object-cover" />
                      <button 
                        onClick={() => handleRemoveAsset(item.id)}
                        className="absolute top-2 right-2 bg-red-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                      >✕</button>
                    </div>
                  ))}
                  {group.items.length === 0 && <p className="col-span-full text-center py-10 text-gray-300 text-xs italic">该分类下暂无收藏材料</p>}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

