            <div className="flex bg-black p-1 rounded-2xl mb-8 border border-white/5">
              <button 
                onClick={() => setRole('DESIGNER')}
                className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${role === 'DESIGNER' ? 'bg-neutral-800 text-white shadow-lg' : 'text-neutral-600'}`}
