import React, { useState } from 'react';
import { User, Material, Category, MoodBoard, PointTransaction, PendingMaterial } from './types';
import { MOCK_MATERIALS } from './constants';
import Navbar from './components/Navbar';
import Auth from './components/Auth';
import PinterestFeed from './components/PinterestFeed';
import CategoryBar from './components/CategoryBar';
import MaterialDetail from './components/MaterialDetail';
import MoodBoardDesigner from './components/MoodBoardDesigner';
import SupplierDashboard from './components/SupplierDashboard';
import DesignerDashboard from './components/DesignerDashboard';
import AdminDashboard from './components/AdminDashboard';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<'HOME' | 'DETAILS' | 'MOODBOARD' | 'DASHBOARD'>('HOME');
  const [selectedMaterial, setSelectedMaterial] = useState<Material | null>(null);
  const [selectedCategory, setSelectedCategory] = useState<Category | null>(null);
  const [points, setPoints] = useState(1000); 

  // Core Data States
  const [library, setLibrary] = useState<Material[]>(MOCK_MATERIALS);
  const [pendingMaterials, setPendingMaterials] = useState<PendingMaterial[]>([]);
  const [moodboards, setMoodboards] = useState<MoodBoard[]>([
    { id: 'mb_1', name: '深圳保利剧院项目', items: [], isPaid: false, maxMaterials: 10 }
  ]);
  const [activeMoodboardId, setActiveMoodboardId] = useState<string>('mb_1');
  const [savedMaterialIds, setSavedMaterialIds] = useState<string[]>([]);

  const handleAuthSuccess = (userData: User) => {
    setUser({ ...userData, transactions: [] });
    setPoints(userData.points);
    setCurrentView('HOME');
  };

  const handleSaveMaterial = (matId: string) => {
    setSavedMaterialIds(prev => {
      const isSaved = prev.includes(matId);
      const newSaved = isSaved ? prev.filter(id => id !== matId) : [...prev, matId];
      setLibrary(prevLib => prevLib.map(m => 
        m.id === matId ? { ...m, saves: isSaved ? m.saves - 1 : m.saves + 1 } : m
      ));
      return newSaved;
    });
  };

  const handlePointChange = (amount: number, desc: string) => {
    setPoints(p => p + amount);
    if (user) {
      const newTransaction: PointTransaction = {
        id: Math.random().toString(),
        amount,
        date: new Date().toISOString(),
        description: desc
      };
      setUser({ ...user, transactions: [...(user.transactions || []), newTransaction] });
    }
  };

  if (!user) {
    return <Auth onAuthSuccess={handleAuthSuccess} />;
  }

  return (
    <div className="min-h-screen bg-black text-white selection:bg-white selection:text-black">
      <Navbar 
        user={user} 
        points={points} 
        onLogoClick={() => setCurrentView('HOME')} 
        onProfileClick={() => setCurrentView('DASHBOARD')}
        onMoodboardClick={() => setCurrentView('MOODBOARD')}
        onLogout={() => setUser(null)}
      />

      <main className="pt-20 px-4 md:px-8 max-w-[100vw] overflow-x-hidden">
        {currentView === 'HOME' && (
          <div className="max-w-7xl mx-auto w-full">
            <CategoryBar 
              selected={selectedCategory} 
              onSelect={setSelectedCategory} 
            />
            <PinterestFeed 
              materials={library.filter(m => !selectedCategory || m.category === selectedCategory)} 
              onSelect={(m) => { setSelectedMaterial(m); setCurrentView('DETAILS'); }}
              onSave={handleSaveMaterial}
              savedIds={savedMaterialIds}
            />
          </div>
        )}

        {currentView === 'DETAILS' && selectedMaterial && (
          <MaterialDetail 
            material={selectedMaterial} 
            user={user}
            onBack={() => setCurrentView('HOME')}
            onDeductPoints={(amt) => handlePointChange(-amt, '材料小样支付')}
          />
        )}

        {currentView === 'MOODBOARD' && (
          <div className="max-w-7xl mx-auto w-full h-full">
            <MoodBoardDesigner 
              user={user}
              points={points}
              materials={library}
              moodboards={moodboards}
              setMoodboards={setMoodboards}
              activeMoodboardId={activeMoodboardId}
              setActiveMoodboardId={setActiveMoodboardId}
              onDeductPoints={(amt, desc) => handlePointChange(-amt, desc)}
            />
          </div>
        )}

        {currentView === 'DASHBOARD' && (
          <div className="max-w-7xl mx-auto w-full">
            {user.role === 'ADMIN' ? (
              <AdminDashboard 
                user={user} 
                library={library}
                setLibrary={setLibrary}
                pendingList={pendingMaterials}
                onApprove={(id) => {}}
              />
            ) : user.role === 'DESIGNER' ? (
              <DesignerDashboard 
                user={user} 
                savedIds={savedMaterialIds} 
                setSavedIds={setSavedMaterialIds} 
                moodboards={moodboards} 
                library={library} 
              />
            ) : (
              <SupplierDashboard 
                user={user} 
                onSubmitForReview={(mat) => setPendingMaterials([...pendingMaterials, mat])} 
              />
            )}
          </div>
        )}
      </main>

      <footer className="py-12 text-center text-[10px] font-black uppercase text-neutral-800 tracking-widest border-t border-white/5 mt-20">
        &copy; 2024 MATERIAL MATTERS. Digital Asset Management.
      </footer>
    </div>
  );
};

export default App;

