import React, { useState } from 'react';
import { User, UserRole } from '../types';

interface AuthProps {
  onAuthSuccess: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onAuthSuccess }) => {
  const [role, setRole] = useState<UserRole>('DESIGNER');
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [adminMode, setAdminMode] = useState(false);
  const [adminPass, setAdminPass] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminMode) {
      if (adminPass === 'admin123') {
        onAuthSuccess({
          id: 'admin_root',
          name: '平台运营主控',
          email: 'admin@materialmatters.com',
          role: 'ADMIN',
          points: 999999
        });
      } else {
        alert('密钥验证失败，请重新输入');
      }
      return;
    }

    const mockUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email: email || 'user@material.com',
      name: email.split('@')[0] || (role === 'DESIGNER' ? '首席设计师' : '材料供应商'),
      role: role,
      points: 1000,
      company: role === 'SUPPLIER' ? '大理石工业集团' : '意式极简工作室'
    };
    onAuthSuccess(mockUser);
  };

  return (
    <div className="min-h-screen bg-black text-white flex flex-col items-center justify-center p-6 relative overflow-hidden">
      {/* Dynamic Background Glow */}
      <div className="absolute top-[-20%] right-[-10%] w-[70vw] h-[70vw] bg-white/5 rounded-full blur-[150px]"></div>
      <div className="absolute bottom-[-10%] left-[-10%] w-[50vw] h-[50vw] bg-neutral-800/10 rounded-full blur-[120px]"></div>

      <div className="w-full max-w-[450px] bg-neutral-900/60 backdrop-blur-3xl border border-white/10 p-12 md:p-16 rounded-[64px] shadow-2xl relative z-10">
        <div className="text-center mb-14">
          <div className="text-4xl font-black bg-white text-black inline-block px-10 py-4 mb-4 tracking-tighter rounded-[28px] transform hover:scale-105 transition-transform">
            MATERIAL <span className="opacity-40 font-light italic">MATTERS</span>
          </div>
          <p className="text-neutral-500 text-[11px] font-black uppercase tracking-[0.5em] mt-3">Professional Hub</p>
        </div>

        {!adminMode ? (
          <>
            <div className="flex bg-black/40 p-2 rounded-[32px] mb-12 border border-white/5">
              <button 
                onClick={() => setRole('DESIGNER')}
                className={`flex-1 py-5 rounded-[24px] text-[12px] font-black uppercase tracking-widest transition-all ${role === 'DESIGNER' ? 'bg-neutral-800 text-white shadow-xl' : 'text-neutral-600 hover:text-neutral-400'}`}
              >
                设计师
              </button>
              <button 
                onClick={() => setRole('SUPPLIER')}
                className={`flex-1 py-5 rounded-[24px] text-[12px] font-black uppercase tracking-widest transition-all ${role === 'SUPPLIER' ? 'bg-neutral-800 text-white shadow-xl' : 'text-neutral-600 hover:text-neutral-400'}`}
              >
                材料商
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="space-y-3">
                <label className="block text-[11px] font-black uppercase text-neutral-600 tracking-[0.3em] ml-4">识别邮箱</label>
                <input 
                  required
                  type="email" 
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="name@studio.com"
                  className="w-full p-6 bg-black border border-white/5 rounded-[36px] text-white outline-none focus:border-white/30 transition-all placeholder:text-neutral-800 text-base"
                />
              </div>
              <div className="space-y-3">
                <label className="block text-[11px] font-black uppercase text-neutral-600 tracking-[0.3em] ml-4">安全密码</label>
                <input 
                  required
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full p-6 bg-black border border-white/5 rounded-[36px] text-white outline-none focus:border-white/30 transition-all placeholder:text-neutral-800 text-base"
                />
              </div>
              <button 
                type="submit"
                className="w-full bg-white text-black py-6 rounded-[36px] font-black uppercase tracking-widest text-sm mt-10 hover:bg-neutral-200 active:scale-[0.98] transition-all shadow-2xl"
              >
                {isLogin ? '认证并进入空间' : '创建数字身份'}
              </button>
            </form>
          </>
        ) : (
          <form onSubmit={handleSubmit} className="space-y-10 animate-in fade-in zoom-in duration-500">
            <div className="text-center">
              <span className="text-yellow-500 text-[11px] font-black uppercase tracking-[0.4em] bg-yellow-500/10 px-8 py-3 rounded-full border border-yellow-500/20">
                OPERATOR LOGIN
              </span>
            </div>
            <div className="space-y-4">
              <label className="block text-center text-[11px] font-black uppercase text-neutral-500 tracking-widest">请输入运营管理密钥</label>
              <input 
                required
                type="password" 
                autoFocus
                placeholder="键入后台密码"
                value={adminPass}
                onChange={(e) => setAdminPass(e.target.value)}
                className="w-full p-10 bg-black border border-white/20 rounded-[40px] text-white text-center outline-none focus:border-white/50 transition-all font-black text-3xl"
              />
            </div>
            <div className="flex gap-4">
              <button type="button" onClick={() => {setAdminMode(false); setAdminPass('')}} className="flex-1 py-6 text-sm font-black text-neutral-500 uppercase tracking-widest">取消</button>
              <button 
                type="submit" 
                className="flex-1 bg-white text-black py-6 rounded-[36px] font-black uppercase tracking-widest text-sm shadow-2xl hover:bg-neutral-200 transition-all"
              >
                验证后台
              </button>
            </div>
          </form>
        )}

        {!adminMode && (
          <div className="mt-14 text-center">
            <button 
              onClick={() => setIsLogin(!isLogin)}
              className="text-[10px] font-black text-neutral-700 hover:text-white uppercase tracking-widest transition-colors"
            >
              {isLogin ? '没有通行账号? 申请加入' : '已有账号? 返回登录'}
            </button>
          </div>
        )}
      </div>

      {/* The Little Key - Hidden Admin Entry */}
      <button 
        onClick={() => setAdminMode(true)}
        className="absolute bottom-12 p-6 opacity-5 hover:opacity-100 transition-all duration-1000 group rounded-full border border-transparent hover:border-white/10"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-neutral-400 group-hover:text-yellow-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" />
        </svg>
      </button>
    </div>
  );
};

export default Auth;

